import React, { useCallback, useEffect, useState } from 'react';
import { Loader, Plus, Save, Search, Trash2 } from 'lucide-react';
import api from '../../services/api';

const emptyItem = { productId: '', quantity: 1, price: 0 };

const StockIns = () => {
  const [rows, setRows] = useState([]);
  const [suppliers, setSuppliers] = useState([]);
  const [products, setProducts] = useState([]);
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState({
    supplierId: '',
    stockInDate: new Date().toISOString().slice(0, 10),
    items: [emptyItem],
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const [stockInRes, supplierRes, productRes] = await Promise.all([
        api.get('/stockins'),
        api.get('/suppliers'),
        api.get('/products'),
      ]);
      setRows(stockInRes.data || []);
      setSuppliers(supplierRes.data || []);
      setProducts(productRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load stock-ins.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const changeItem = (idx, key, value) => {
    const copy = [...form.items];
    copy[idx] = { ...copy[idx], [key]: value };
    setForm({ ...form, items: copy });
  };

  const addItem = () => setForm({ ...form, items: [...form.items, emptyItem] });
  const removeItem = (idx) => setForm({ ...form, items: form.items.filter((_, i) => i !== idx) });

  const onSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError('');
    try {
      const payload = {
        supplierId: parseInt(form.supplierId, 10),
        stockInDate: form.stockInDate,
        items: form.items.map((i) => ({
          productId: parseInt(i.productId, 10),
          quantity: parseInt(i.quantity, 10),
          price: parseFloat(i.price),
        })),
      };

      if (editingId) {
        await api.put(`/stockins/${editingId}`, payload);
      } else {
        await api.post('/stockins', payload);
      }

      setEditingId(null);
      setForm({ supplierId: '', stockInDate: new Date().toISOString().slice(0, 10), items: [emptyItem] });
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save stock-in.');
    } finally {
      setSaving(false);
    }
  };

  const onEdit = (row) => {
    setEditingId(row.stockInId);
    setForm({
      supplierId: row.supplierId,
      stockInDate: new Date(row.stockInDate).toISOString().slice(0, 10),
      items: (row.stockInDetails || []).map((d) => ({
        productId: d.productId,
        quantity: d.quantity,
        price: d.price,
      })),
    });
  };

  const onDelete = async (id) => {
    if (!window.confirm('Delete this stock-in record?')) return;
    try {
      await api.delete(`/stockins/${id}`);
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to delete stock-in.');
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Stock In</h2>
      {error && <div className="p-3 text-sm border border-red-200 bg-red-50 text-red-700 rounded-lg">{error}</div>}

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
        <input
          type="text"
          placeholder="Search by supplier..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      <form onSubmit={onSubmit} className="bg-white border border-gray-200 rounded-xl p-4 space-y-3">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <select value={form.supplierId} onChange={(e) => setForm({ ...form, supplierId: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" required>
            <option value="">Select supplier</option>
            {suppliers.map((s) => <option key={s.supplierId} value={s.supplierId}>{s.supplierName}</option>)}
          </select>
          <input type="date" value={form.stockInDate} onChange={(e) => setForm({ ...form, stockInDate: e.target.value })} className="px-3 py-2 border border-gray-300 rounded-lg" required />
        </div>

        <div className="space-y-2">
          {form.items.map((item, idx) => (
            <div key={idx} className="grid grid-cols-1 md:grid-cols-4 gap-2">
              <select value={item.productId} onChange={(e) => changeItem(idx, 'productId', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" required>
                <option value="">Select product</option>
                {products.map((p) => <option key={p.productId} value={p.productId}>{p.productName}</option>)}
              </select>
              <input type="number" min="1" value={item.quantity} onChange={(e) => changeItem(idx, 'quantity', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="Qty" required />
              <input type="number" min="0" step="0.01" value={item.price} onChange={(e) => changeItem(idx, 'price', e.target.value)} className="px-3 py-2 border border-gray-300 rounded-lg" placeholder="Price" required />
              <button type="button" onClick={() => removeItem(idx)} className="px-3 py-2 rounded-lg bg-red-50 text-red-600 border border-red-200 disabled:opacity-40" disabled={form.items.length === 1}>Remove</button>
            </div>
          ))}
        </div>

        <div className="flex flex-wrap gap-2">
          <button type="button" onClick={addItem} className="inline-flex items-center gap-2 px-3 py-2 rounded-lg bg-gray-100 text-gray-700"><Plus className="w-4 h-4" /> Add Item</button>
          <button type="submit" disabled={saving} className="inline-flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white"><Save className="w-4 h-4" /> {editingId ? 'Update' : 'Create'}</button>
          {editingId && <button type="button" onClick={() => { setEditingId(null); setForm({ supplierId: '', stockInDate: new Date().toISOString().slice(0, 10), items: [emptyItem] }); }} className="px-4 py-2 rounded-lg bg-gray-200">Cancel</button>}
        </div>
      </form>

      <div className="bg-white border border-gray-200 rounded-xl overflow-x-auto">
        {loading ? <div className="py-10 flex justify-center"><Loader className="w-6 h-6 animate-spin text-blue-600" /></div> : (
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Date</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Supplier</th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Items</th>
                <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 uppercase">Total Qty</th>
                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Actions</th>
              </tr>
            </thead>
            <tbody>
              {rows.filter((r) => {
                const q = search.toLowerCase();
                return !q || (r.supplier?.supplierName || '').toLowerCase().includes(q);
              }).map((r) => {
                const details = r.stockInDetails || [];
                const totalQty = details.reduce((sum, d) => sum + d.quantity, 0);
                return (
                  <tr key={r.stockInId} className="border-t border-gray-100">
                    <td className="px-4 py-3">{new Date(r.stockInDate).toLocaleDateString()}</td>
                    <td className="px-4 py-3">{r.supplier?.supplierName || '-'}</td>
                    <td className="px-4 py-3 text-right">{details.length}</td>
                    <td className="px-4 py-3 text-right font-semibold">{totalQty}</td>
                    <td className="px-4 py-3">
                      <div className="flex gap-2">
                        <button onClick={() => onEdit(r)} className="px-3 py-1 rounded bg-blue-50 text-blue-600">Edit</button>
                        <button onClick={() => onDelete(r.stockInId)} className="inline-flex items-center gap-1 px-3 py-1 rounded bg-red-50 text-red-600"><Trash2 className="w-3 h-3" />Delete</button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default StockIns;
